#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=2e5+10;long long ans;int stk[N*10],top;
struct Seg{int l,r,sum;}t[N*30];int cnt,n,Rt;long long u,v;
inline void Rcy(int k){if(top<N*10-1)stk[++top]=k;}
inline int New(){int q=top?stk[top--]:++cnt;t[q].l=t[q].r=t[q].sum=0;return q;}
inline void update(int cur){t[cur].sum=t[t[cur].l].sum+t[t[cur].r].sum;}
inline void build(int l,int r,int &cur,int val)
{
	if(!cur)cur=New();if(l==r){t[cur].sum=(l==val);return;}int mid=(l+r)>>1;
	if(val<=mid)build(l,mid,t[cur].l,val);else build(mid+1,r,t[cur].r,val);update(cur);
}
inline int merge(int kl,int kr,int l,int r)
{
	if(!kl||!kr)return kl|kr;if(l==r){t[kl].sum+=t[kr].sum;Rcy(kr);return kl;}
	int mid=(l+r)>>1;u+=1ll*t[t[kl].l].sum*t[t[kr].r].sum;v+=1ll*t[t[kr].l].sum*t[t[kl].r].sum;
	t[kl].l=merge(t[kl].l,t[kr].l,l,mid);t[kl].r=merge(t[kl].r,t[kr].r,mid+1,r);
	Rcy(kr);update(kl);return kl; 
}
inline void dfs(int &cur)
{
	int val=read();if(!val)
	{
		
		int l=0,r=0;dfs(l);dfs(r);
		u=v=0;cur=merge(l,r,1,n);ans+=min(u,v);
	}
	else {build(1,n,cur,val);}
}
int main(){
//freopen("qnmd.txt","r",stdin);
n=read();dfs(Rt);printf("%lld\n",ans);}
